// src/auth/github-auth.ts
import { writeFileSync as writeFileSync7, readFileSync as readFileSync9, existsSync as existsSync12, mkdirSync as mkdirSync5, chmodSync as chmodSync2 } from "fs";
import { join as join11 } from "path";
import { homedir as homedir2 } from "os";
var TOKEN_PATH = join11(homedir2(), ".nexarq", ".token");
var GITHUB_CLIENT_ID = process.env["NEXARQ_GITHUB_CLIENT_ID"] ?? "";
async function startGitHubDeviceFlow() {
  if (!GITHUB_CLIENT_ID) {
    throw new Error("NEXARQ_GITHUB_CLIENT_ID not configured");
  }
  const deviceResponse = await fetch("https://github.com/login/device/code", {
    method: "POST",
    headers: { Accept: "application/json", "Content-Type": "application/json" },
    body: JSON.stringify({ client_id: GITHUB_CLIENT_ID, scope: "read:user" })
  });
  const deviceData = await deviceResponse.json();
  console.log(`
  Go to: ${deviceData.verification_uri}`);
  console.log(`  Enter code: ${deviceData.user_code}
`);
  try {
    const open2 = await Promise.resolve().then(() => (init_open(), exports_open));
    await open2.default(deviceData.verification_uri);
  } catch {}
  const token = await pollForToken(deviceData.device_code, deviceData.interval);
  const userResponse = await fetch("https://api.github.com/user", {
    headers: { Authorization: `Bearer ${token}`, Accept: "application/vnd.github+json" }
  });
  const userData = await userResponse.json();
  mkdirSync5(join11(homedir2(), ".nexarq"), { recursive: true });
  writeFileSync7(TOKEN_PATH, JSON.stringify({ token, username: userData.login }), "utf-8");
  chmodSync2(TOKEN_PATH, 384);
  return { token, username: userData.login, name: userData.name ?? userData.login };
}
async function pollForToken(deviceCode, intervalSeconds) {
  const maxAttempts = 30;
  let attempts = 0;
  while (attempts < maxAttempts) {
    await sleep3(intervalSeconds * 1000);
    attempts++;
    const tokenResponse = await fetch("https://github.com/login/oauth/access_token", {
      method: "POST",
      headers: { Accept: "application/json", "Content-Type": "application/json" },
      body: JSON.stringify({
        client_id: GITHUB_CLIENT_ID,
        device_code: deviceCode,
        grant_type: "urn:ietf:params:oauth:grant-type:device_code"
      })
    });
    const tokenData = await tokenResponse.json();
    if (tokenData.access_token)
      return tokenData.access_token;
    if (tokenData.error === "access_denied")
      throw new Error("Login cancelled");
    if (tokenData.error === "expired_token")
      throw new Error("Device code expired \u2014 try again");
  }
  throw new Error("Login timed out");
}
function sleep3(milliseconds) {
  return new Promise((resolve4) => setTimeout(resolve4, milliseconds));
}

