import { watch } from "fs";
import { execSync as execSync7 } from "child_process";
function watchCommand() {
  return new Command("watch").description("Review code changes live as you save files").option("-d, --dir <path>", "Directory to watch (default: current directory)").action(async (options) => {
    const config2 = await loadConfig2();
    const watchDir = options.dir ?? process.cwd();
    const tui = await createPageTUI("WATCH", "FINDINGS", { exitOnCtrlC: false });
    tui.status.content = `  Watching ${watchDir}  \xB7  Ctrl+C to stop`;
    let debounceTimer = null;
    let isReviewing = false;
    async function runReview() {
      if (isReviewing)
        return;
      isReviewing = true;
      tui.status.content = "  Reviewing...";
      try {
        const rawDiff = execSync7("git diff", { encoding: "utf-8", cwd: watchDir }).trim();
        if (!rawDiff) {
          tui.status.content = "  No unstaged changes \u2014 watching...";
          isReviewing = false;
          return;
        }
        tui.clearBody();
        tui.body.add(Text({ content: "  Running agents...", fg: THEME.fgDim }));
        const result = await runOrchestrator({
          task: "Review the following diff",
          diffResult: makeDiffResult(rawDiff),
          triggerSource: "on-demand",
          runConfig: {
            provider: config2.provider,
            ...config2.model ? { model: config2.model } : {},
            mode: "fast"
          }
        });
        tui.clearBody();
        if (result.summary.totalFindings === 0) {
          tui.body.add(Text({ content: "  No issues found.", fg: THEME.green }));
        } else {
          for (const agentResult of result.results) {
            for (const finding of agentResult.findings) {
              const color2 = THEME.severity[finding.severity] ?? THEME.fg;
              tui.body.add(Text({
                content: `  [${finding.severity?.toUpperCase() ?? "INFO"}] ${finding.message}`,
                fg: color2
              }));
              if (finding.file) {
                tui.body.add(Text({
                  content: `    ${finding.file}${finding.line ? `:${finding.line}` : ""}`,
                  fg: THEME.fgDim
                }));
              }
            }
          }
        }
        const { critical, high, medium, low } = result.summary;
        tui.status.content = `  Last review: ${critical}c ${high}h ${medium}m ${low}l  \xB7  watching...`;
      } catch {
        tui.status.content = "  Review failed \u2014 watching...";
      } finally {
        isReviewing = false;
      }
    }
    const watcher = watch(watchDir, { recursive: true }, (_2, filename) => {
      if (!filename)
        return;
      if (filename.includes("node_modules") || filename.includes(".git"))
        return;
      if (!filename.match(/\.(ts|tsx|js|jsx|py|go|rs|java|cs|rb|php|css|html|json|yaml|yml|sql)$/))
        return;
      if (debounceTimer)
        clearTimeout(debounceTimer);
      debounceTimer = setTimeout(() => void runReview(), 2000);
    });
    runReview();
    tui.renderer.keyInput.on("keypress", (event) => {
      if (event.ctrl && event.name === "c") {
        watcher.close();
        tui.renderer.destroy();
        process.exit(0);
      }
    });
  });
}

