program2.action(async () => {
  if (isFirstRun()) {
    const { runWelcomeScreen: runWelcomeScreen2 } = await Promise.resolve().then(() => (init_welcome_tui(), exports_welcome_tui));
    const { runInitWizard: runInitWizard2 } = await Promise.resolve().then(() => (init_init_tui(), exports_init_tui));
    const { getThemeByVariant: getThemeByVariant2 } = await Promise.resolve().then(() => (init_theme(), exports_theme));
    const { saveConfig: saveConfig2 } = await Promise.resolve().then(() => (init_config_loader(), exports_config_loader));
    const { storeApiKey: storeApiKey2 } = await Promise.resolve().then(() => exports_keyring);
    const { installHook: installHook2 } = await Promise.resolve().then(() => (init_hook_installer(), exports_hook_installer));
    try {
      const variant = await runWelcomeScreen2();
      const theme = getThemeByVariant2(variant);
      const wizard = await runInitWizard2(theme);
      if (wizard.apiKey)
        await storeApiKey2(wizard.provider, wizard.apiKey);
      await saveConfig2({
        provider: wizard.provider,
        cloudConsent: wizard.cloudConsent,
        theme: variant
      });
      if (wizard.installPostCommit)
        await installHook2("post-commit");
      if (wizard.installPrePush)
        await installHook2("pre-push");
    } catch (err) {
      const { printError: printError2 } = await Promise.resolve().then(() => (init_formatter(), exports_formatter));
      printError2(err instanceof Error ? err.message : String(err));
      process.exit(1);
    }
  } else {
    program2.help();
  }
});
program2.addCommand(runCommand());
program2.addCommand(codeCommand());
program2.addCommand(commitCommand());
program2.addCommand(fixCommand());
program2.addCommand(watchCommand());
program2.addCommand(explainCommand());
program2.addCommand(chatCommand());
program2.addCommand(ignoreCommand());
program2.addCommand(initCommand());
program2.addCommand(hookCommand());
program2.addCommand(configCommand());
program2.addCommand(loginCommand());
program2.addCommand(doctorCommand());
program2.parse();
